import kotlin.math.*

fun gcd(a: Long, b: Long): Long {
    return if (b == 0L) a else gcd(b, a % b)
}

fun computeGCD(arr: List<Long>): Long {
    return arr.reduce { a, b -> gcd(a, b) }
}

fun solve(nums: Array<Long>, maxC: Long): Long {
    val n = nums.size
    var low = 1L
    var high = n.toLong()
    var answer = 0L

    while (low <= high) {
        val mid = (low + high) / 2
        var allUnstable = true
        for (i in 0..(n - mid.toInt())) {
            val window = nums.slice(i until i + mid.toInt())
            val windowGCD = computeGCD(window)
            val changesNeeded = if (windowGCD >= 2L) 1L else 0L
            if (changesNeeded > maxC) {
                allUnstable = false
                break
            }
        }
        if (allUnstable) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return if (answer == n.toLong()) 0 else answer
}
